import{c as s,S as a,j as n,m as o}from"./chunks/framework.DvQr6YbT.js";const g=JSON.parse('{"title":"技术架构","description":"","frontmatter":{},"headers":[],"relativePath":"zh/developer/architecture.md","filePath":"zh/developer/architecture.md","lastUpdated":1783497907000}'),t={name:"zh/developer/architecture.md"};function d(c,e,r,i,l,p){return a(),n("div",null,[...e[0]||(e[0]=[o(`<h1 id="技术架构" tabindex="-1">技术架构 <a class="header-anchor" href="#技术架构" aria-label="Permalink to “技术架构”">​</a></h1><p>Knowlery 的组装方式：一个平台无关的核心、三个薄壳层，以及一套全员共享的、 基于纯 markdown 的工作区格式。</p><h2 id="一核三壳" tabindex="-1">一核三壳 <a class="header-anchor" href="#一核三壳" aria-label="Permalink to “一核三壳”">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>                    ┌─────────────────────────────┐</span></span>
<span class="line"><span>                    │        src/core/            │</span></span>
<span class="line"><span>                    │   检索 · 陈旧检测 · 同步 ·   │</span></span>
<span class="line"><span>                    │   初始化 · 知识包 · 注册表 · │</span></span>
<span class="line"><span>                    │      MCP 处理器             │</span></span>
<span class="line"><span>                    └──────┬───────┬───────┬──────┘</span></span>
<span class="line"><span>                           │       │       │</span></span>
<span class="line"><span>              ┌────────────┴─┐  ┌──┴────┐  └──────────────┐</span></span>
<span class="line"><span>              │ Obsidian     │  │ CLI   │  │ MCP 服务器    │</span></span>
<span class="line"><span>              │ 插件         │  │       │  │ (stdio/HTTP)  │</span></span>
<span class="line"><span>              │ (main.js)    │  │       │  │               │</span></span>
<span class="line"><span>              └──────────────┘  └───────┘  └───────────────┘</span></span></code></pre></div><ul><li><strong>核心</strong>（<code>src/core/</code>）承载全部生命周期逻辑：初始化、同步、检索、陈旧 检测、知识包导出/安装/发布/更新、KB 注册表、MCP 工具处理器。它从不以值 的形式导入 Obsidian API——有一个测试 （<code>tests/core/core-purity.test.ts</code>）枚举所有倒置模块，任何非 type-only 的 <code>import ... from &#39;obsidian&#39;</code> 都会让它失败。</li><li><strong>Obsidian 插件</strong>（<code>src/main.ts</code>、views、modals）添加评审 UI：dashboard、 导出/安装弹窗、设置、Freshness Review。</li><li><strong>CLI</strong>（<code>src/cli/</code>）是薄薄的 argv/prompt/输出层。命令只解析旗标然后委托； 壳层里不放生命周期逻辑。</li><li><strong>MCP 服务器</strong>（<code>src/core/mcp/</code>）把同样的操作暴露为工具、提示词和资源。 stdio 壳（<code>knowlery mcp</code>）和 HTTP 壳（<code>knowlery mcp serve</code>）提供传输层； 处理器不知道自己运行在哪个传输层上。</li></ul><p>一个仓库产出两个 esbuild 产物：<code>main.js</code>（插件）和 <code>knowlery-cli.mjs</code> （CLI + MCP）。MCP SDK 只打进 CLI 产物——插件包里没有任何 MCP 代码。</p><h2 id="文件系统倒置" tabindex="-1">文件系统倒置 <a class="header-anchor" href="#文件系统倒置" aria-label="Permalink to “文件系统倒置”">​</a></h2><p>核心通过 <code>VaultFs</code> 接口（<code>src/core/vault-fs.ts</code>）访问磁盘，有两个实现：</p><table tabindex="0"><thead><tr><th>实现</th><th>底层</th><th>使用方</th></tr></thead><tbody><tr><td><code>obsidianVaultFs</code></td><td>Obsidian <code>App</code> vault API</td><td>插件</td></tr><tr><td><code>nodeVaultFs</code></td><td><code>node:fs</code></td><td>CLI、MCP、测试</td></tr></tbody></table><p><code>loggingVaultFs</code> 可以包装任意一个，记录一次 sync 实际写了哪些路径——<code>sync</code> 的文件清单和测试里的幂等性证明都来自它。Wikilink 解析同样分裂：插件用 Obsidian 的 <code>metadataCache</code>；无头代码扫描文件，且有歧义的 basename 解析为 空而不是猜测。</p><h2 id="工作区格式" tabindex="-1">工作区格式 <a class="header-anchor" href="#工作区格式" aria-label="Permalink to “工作区格式”">​</a></h2><p>Knowlery 工作区就是一个普通文件夹：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>KNOWLEDGE.md          # 面向 agent 的操作指南</span></span>
<span class="line"><span>SCHEMA.md             # 活的分类约定</span></span>
<span class="line"><span>INDEX.base            # Obsidian Bases 索引</span></span>
<span class="line"><span>entities/ concepts/ comparisons/ queries/    # 编译层（agent 层级）</span></span>
<span class="line"><span>inbox/                # MCP capture 落点（用户层级，按需创建）</span></span>
<span class="line"><span>Library/&lt;bundle-id&gt;/  # 已安装知识包（只读参考）</span></span>
<span class="line"><span>.knowlery/            # manifest、bundles.json、导出、活动、报告</span></span>
<span class="line"><span>.agents/skills/ .claude/skills/              # 已安装技能包</span></span></code></pre></div><p>页面是带 frontmatter 的 markdown。扫描器（<code>src/core/query/scan.ts</code>）把每个 页面归入层级：<code>agent</code>（四个编译目录）、<code>user</code>（其余一切），以及 <code>Library/</code> 下的知识包材料。这个层级驱动检索加权、陈旧检测和 MCP 资源白名单。</p><p>manifest（<code>.knowlery/manifest.json</code>）记录平台、KB 名称和 <code>lastSyncedBy</code>—— 降级守卫背后的版本戳。</p><h2 id="检索引擎" tabindex="-1">检索引擎 <a class="header-anchor" href="#检索引擎" aria-label="Permalink to “检索引擎”">​</a></h2><p><code>src/core/query/</code> 是纯 TypeScript，除初始扫描外没有任何 I/O：</p><ol><li><strong>分词</strong>：拉丁词带轻量词形变体，CJK 子串和短语。</li><li><strong>打分</strong>：字段加权——标题和别名权重最高，其次 tag、描述、正文。当编译 页面引用（<code>sources:</code>）的原始笔记命中问题时，该编译页面获得加分——跨语言 提问就是这样抵达编译层答案的。</li><li><strong>门禁</strong>：top 候选必须过置信线——结构化字段命中且特异性加权的词覆盖率 足够、散文覆盖强，或纯 source-graph 触达。否则判定为 <code>no-confident-match</code>，引擎弃答而不是排列噪音。</li></ol><p>刻意<strong>没有缓存、没有索引</strong>：每次查询都是实时扫描。vault 规模的语料毫秒级 扫完，无状态则彻底消除了失效问题——正是这个性质后来让 MCP 服务器白拿了 重启安全。</p><p>同一份快照喂给<strong>陈旧检测</strong>（<code>staleness.ts</code>）：被引用来源的 mtime 比页面新 即为 stale；无人引用的用户笔记是&quot;未编译&quot;；指向不存在文件的引用是 dangling。 一切都从 mtime 现算——没有簿记状态。</p><p>检索质量<strong>靠测量而非断言</strong>：<code>evals/</code> 有 fixture vault 和黄金问题集；CI 对 冻结基线跑 recall@10 / MRR，低于基线的变更直接失败。</p><h2 id="知识包-okf" tabindex="-1">知识包（OKF） <a class="header-anchor" href="#知识包-okf" aria-label="Permalink to “知识包（OKF）”">​</a></h2><p>知识包是一个 zip：已批准的编译页面，加 <code>knowlery-bundle.json</code>（manifest： id、版本、创建者、内容哈希）、用于导航的 <code>index.md</code> 和 <code>agent-index.json</code>、 <code>_sources/</code> 下已批准的原始来源，以及只覆盖包内实际使用的 tag 的 schema。</p><p>管线（<code>src/core/okf/</code>）是门禁形状的：</p><ul><li><strong>导出</strong>：种子主题 → 图闭包 → 逐项评审（approve/flag 带内容哈希，编辑会 使批准自动失效）→ 风险扫描（邮箱、敏感 URL、凭证模式、人物页）→ 编译 → 打包。</li><li><strong>发布</strong>：<code>gh</code> CLI 创建 GitHub Release，notes 里带 SHA-256；公开仓库需要 对每个风险项二次确认。</li><li><strong>安装</strong>：本地路径或 URL；私有 Release 资产通过用户的 <code>gh</code> 登录下载； <code>--verify &lt;sha256&gt;</code> 校验完整性；写入前先做 conformance 结构校验。</li><li><strong>更新</strong>：<code>check-updates</code> 只读地查询 Release 源；<code>update</code> 要求版本递增、 在临时目录 staging 新内容、按哈希检测本地修改、带备份的原子交换。</li></ul><h2 id="kb-注册表" tabindex="-1">KB 注册表 <a class="header-anchor" href="#kb-注册表" aria-label="Permalink to “KB 注册表”">​</a></h2><p><code>~/.config/knowlery/registry.json</code> 把名字映射到规范路径——仅此而已。所有壳 层共享它：CLI 的 <code>--kb</code>、插件的自注册（带所有权追踪，绝不删除用户自己的 条目）、MCP 服务器的寻址层。名字在写入<em>和</em>读取时都校验（手改出的非法条目 是响亮的错误，绝不静默丢数据）。联邦查询遍历注册表、逐 KB 跑引擎、按分数 合并并逐条标注来源。</p><h2 id="mcp-服务器" tabindex="-1">MCP 服务器 <a class="header-anchor" href="#mcp-服务器" aria-label="Permalink to “MCP 服务器”">​</a></h2><p><code>src/core/mcp/server.ts</code> 在 SDK 的 <code>McpServer</code> 上注册一切：</p><ul><li><strong>八个工具</strong>——五读（<code>list_kbs</code>、<code>query</code>、<code>stale</code>、<code>health</code>、 <code>list_bundles</code>）三写（<code>init_kb</code>、<code>capture</code>、<code>sync</code>）——每个都有 zod 输入 schema（strict：拒绝未知字段），<code>structuredContent</code> 与 CLI 的 <code>--json</code> 形状一致。</li><li><strong>提示词</strong>：九个精选技能，原样送出。</li><li><strong>资源</strong>：<code>knowlery://{kb}/{+path}</code>，读取白名单只覆盖精选层 （<code>KNOWLEDGE.md</code>、编译目录、<code>Library/</code>）——先 canonicalize 再前缀检查， 穿越和 symlink 逃逸都被拒绝。</li></ul><p>访问是<strong>结构性的</strong>：<code>access</code> 选项决定哪些写工具被注册。stdio 注册全部 （调用方拥有这台机器）；HTTP 壳 fail closed，只注册 <code>--allow-*</code> 旗标明确 打开的。</p><p>HTTP 壳（<code>http-server.ts</code>）保持一个长命的 <code>node:http</code> server，但<strong>每个请求 新建一对 McpServer + 无状态 transport</strong>，随 response 一起关闭——这是 SDK 无状态模式的契约。认证是 bearer token，<code>timingSafeEqual</code> 比较哈希；token 从不落盘、从不进日志。</p><h2 id="测试策略" tabindex="-1">测试策略 <a class="header-anchor" href="#测试策略" aria-label="Permalink to “测试策略”">​</a></h2><table tabindex="0"><thead><tr><th>层</th><th>方法</th></tr></thead><tbody><tr><td>核心逻辑</td><td>纯函数单测（引擎、陈旧检测、zip、注册表）</td></tr><tr><td>命令处理器</td><td>内存 <code>VaultFs</code> + 临时目录；对清理路径注入故障</td></tr><tr><td>MCP</td><td>SDK 内存 transport 上的协议往返——无子进程</td></tr><tr><td>构建产物</td><td>smoke 测试用发布入口构建 <code>knowlery-cli.mjs</code> 并端到端驱动：init → sync → query → bundles → 远程安装 → 注册表 → MCP stdio → HTTP serve</td></tr><tr><td>检索质量</td><td>eval harness，CI 强制基线</td></tr><tr><td>纯度</td><td>倒置模块清单，测试强制</td></tr></tbody></table><h2 id="版本与发布" tabindex="-1">版本与发布 <a class="header-anchor" href="#版本与发布" aria-label="Permalink to “版本与发布”">​</a></h2><p>插件和 CLI 版本 lockstep（同一个 <code>package.json</code>）。发布由版本 tag 触发； npm 发布用 OIDC trusted publishing（CI 里无 token）带 provenance，且幂等—— 重跑已发布的 tag 会绿色跳过。1.0 起，工作区格式、CLI 表面和 MCP 工具契约 在 semver 下冻结。</p>`,36)])])}const b=s(t,[["render",d]]);export{g as __pageData,b as default};
